/* global Office */

import type { NodeRow } from "../core/astTypes";

type ParentMessage =
  | { action: "setTree"; rootAddress: string; rawFormula: string; nodes: NodeRow[]; parseError?: string }
  | { action: "appendChildren"; parentId: string; children: NodeRow[]; parentPatch?: Partial<NodeRow>; message?: string }
  | { action: "error"; message: string };

let rawFormula = "";
let rows: NodeRow[] = [];
let visibleRows: NodeRow[] = [];
let expanded = new Set<string>();
let loading = new Set<string>();
let selectedIndex = 0;

function send(
  message:
    | { action: "ready" }
    | { action: "navigate"; location: string; locations?: string[] }
    | { action: "expandReference"; row: NodeRow }
    | { action: "close" }
): void {
  Office.context.ui.messageParent(JSON.stringify(message));
}

function parseMessage(raw: unknown): ParentMessage | null {
  if (typeof raw !== "string") return null;
  try {
    const parsed = JSON.parse(raw) as ParentMessage;
    if (parsed.action === "setTree" || parsed.action === "appendChildren" || parsed.action === "error") return parsed;
  } catch {
    return null;
  }
  return null;
}

function childrenOf(id: string): NodeRow[] {
  return rows.filter((row) => row.parentId === id);
}

function parentOf(row: NodeRow): NodeRow | undefined {
  return row.parentId ? rows.find((item) => item.id === row.parentId) : undefined;
}

function isLastChild(row: NodeRow): boolean {
  if (!row.parentId) return true;
  const siblings = childrenOf(row.parentId);
  return siblings[siblings.length - 1]?.id === row.id;
}

function lineageOf(row: NodeRow): NodeRow[] {
  const lineage: NodeRow[] = [];
  let parent = parentOf(row);
  while (parent?.parentId) {
    lineage.unshift(parent);
    parent = parentOf(parent);
  }
  return lineage;
}

function recomputeVisible(): void {
  visibleRows = [];
  const walk = (row: NodeRow): void => {
    visibleRows.push(row);
    if (!expanded.has(row.id)) return;
    childrenOf(row.id).forEach(walk);
  };
  const root = rows.find((row) => row.parentId === null);
  if (root) walk(root);
}

function render(): void {
  recomputeVisible();
  const body = document.getElementById("treeBody");
  if (!(body instanceof HTMLTableSectionElement)) return;
  body.textContent = "";
  visibleRows.forEach((row, index) => {
    const tr = document.createElement("tr");
    tr.tabIndex = 0;
    tr.className = index === selectedIndex ? "selected" : "";
    tr.setAttribute("role", "treeitem");
    tr.setAttribute("aria-level", String(row.level + 1));
    tr.addEventListener("click", () => selectIndex(index, true));
    tr.addEventListener("keydown", handleKey);

    const element = document.createElement("td");
    const treeCell = document.createElement("span");
    treeCell.className = "tree-cell";
    const indent = document.createElement("span");
    indent.className = "indent";
    indent.style.setProperty("--level", String(row.level));
    const lineage = lineageOf(row);
    for (let guideLevel = 1; guideLevel <= row.level; guideLevel += 1) {
      const guide = document.createElement("span");
      const ancestor = lineage.find((item) => item.level === guideLevel);
      const isCurrent = guideLevel === row.level;
      guide.className = isCurrent
        ? `branch-guide branch-elbow${isLastChild(row) ? "" : " branch-through"}`
        : `branch-guide${ancestor && !isLastChild(ancestor) ? " branch-line" : ""}`;
      indent.appendChild(guide);
    }
    const chev = document.createElement("span");
    chev.className = "chevron";
    const canExpand = row.hasChildren || row.canExpandReference;
    chev.classList.toggle("loading", loading.has(row.id));
    chev.classList.toggle("expanded", canExpand && expanded.has(row.id));
    chev.classList.toggle("empty", !canExpand);
    chev.title = canExpand ? (expanded.has(row.id) ? "Collapse" : "Expand") : "";
    chev.textContent = loading.has(row.id) ? "..." : "";
    chev.addEventListener("click", (event) => {
      event.stopPropagation();
      toggle(row.id);
    });
    const text = document.createElement("span");
    text.className = "node-label";
    text.textContent = truncateMiddle(row.element, 52);
    text.title = row.element;
    treeCell.append(indent, chev, text);
    element.append(treeCell);

    const value = document.createElement("td");
    value.textContent = row.value;
    const location = document.createElement("td");
    location.textContent = row.location;
    location.title = (row.locations ?? [row.fullLocation]).filter(Boolean).join(", ");
    tr.append(element, value, location);
    body.appendChild(tr);
  });
  renderPreview(visibleRows[selectedIndex]);
}

function renderPreview(row?: NodeRow): void {
  const target = document.getElementById("preview");
  if (!target) return;
  if (row?.rootPreviewOnly) {
    target.textContent = rawFormula;
    return;
  }
  if (row?.previewText && !row.previewFormula) {
    target.textContent = row.previewText;
    return;
  }
  const formula = row?.previewFormula || rawFormula;
  if (!row || row.start === row.end) {
    target.textContent = formula;
    return;
  }
  target.textContent = "";
  target.append(document.createTextNode(formula.slice(0, row.start)));
  const mark = document.createElement("mark");
  mark.textContent = formula.slice(row.start, row.end);
  target.append(mark, document.createTextNode(formula.slice(row.end)));
  mark.scrollIntoView({ block: "nearest", inline: "nearest" });
}

function selectIndex(index: number, navigate: boolean): void {
  selectedIndex = Math.max(0, Math.min(index, visibleRows.length - 1));
  render();
  const body = document.getElementById("treeBody");
  const selected = body?.querySelectorAll("tr")[selectedIndex];
  if (selected instanceof HTMLTableRowElement) selected.focus();
  const row = visibleRows[selectedIndex];
  if (navigate && row?.fullLocation) sendNavigate(row);
}

function toggle(id: string): void {
  const row = rows.find((item) => item.id === id);
  if (!row || loading.has(id)) return;
  if (!row.hasChildren && row.canExpandReference) {
    loading.add(id);
    render();
    send({ action: "expandReference", row });
    return;
  }
  if (expanded.has(id)) expanded.delete(id);
  else expanded.add(id);
  render();
}

function handleKey(event: KeyboardEvent): void {
  const row = visibleRows[selectedIndex];
  switch (event.key) {
    case "ArrowDown":
      event.preventDefault();
      selectIndex(selectedIndex + 1, true);
      break;
    case "ArrowUp":
      event.preventDefault();
      selectIndex(selectedIndex - 1, true);
      break;
    case "ArrowRight":
      event.preventDefault();
      if (row?.hasChildren && !expanded.has(row.id)) toggle(row.id);
      else selectIndex(selectedIndex + 1, true);
      break;
    case "ArrowLeft":
      event.preventDefault();
      if (row?.hasChildren && expanded.has(row.id)) toggle(row.id);
      else if (row?.parentId) selectIndex(visibleRows.findIndex((item) => item.id === row.parentId), true);
      break;
    case "Home":
      event.preventDefault();
      selectIndex(0, true);
      break;
    case "End":
      event.preventDefault();
      selectIndex(visibleRows.length - 1, true);
      break;
    case "Enter":
      event.preventDefault();
      if (row?.fullLocation) sendNavigate(row);
      break;
    case "Escape":
      event.preventDefault();
      send({ action: "close" });
      break;
  }
}

function applyTree(message: Extract<ParentMessage, { action: "setTree" }>): void {
  rawFormula = message.rawFormula;
  rows = message.nodes;
  expanded = new Set(rows.filter((row) => row.level <= 1 && row.hasChildren).map((row) => row.id));
  selectedIndex = 0;
  const title = document.getElementById("title");
  if (title) title.textContent = `Formula Explorer - ${message.rootAddress}`;
  const status = document.getElementById("status");
  if (status) status.textContent = message.parseError ?? `${rows.length} elements`;
  render();
}

function appendChildren(message: Extract<ParentMessage, { action: "appendChildren" }>): void {
  loading.delete(message.parentId);
  const parent = rows.find((row) => row.id === message.parentId);
  if (!parent) return;
  if (message.parentPatch) Object.assign(parent, message.parentPatch);
  parent.hasChildren = message.children.length > 0;
  parent.canExpandReference = false;
  rows = rows.filter((row) => row.parentId !== message.parentId).concat(message.children);
  expanded.add(message.parentId);
  const status = document.getElementById("status");
  if (status) status.textContent = message.message ?? `${rows.length} elements`;
  render();
}

function copyTreeAsText(): string {
  return rows.map((row) => `${"  ".repeat(row.level)}${row.element}\t${row.value}\t${(row.locations ?? [row.fullLocation]).join(", ")}`).join("\n");
}

function sendNavigate(row: NodeRow): void {
  const locations = row.locations?.length ? row.locations : row.fullLocation ? [row.fullLocation] : [];
  if (locations.length === 0) return;
  send({ action: "navigate", location: locations[0], locations });
}

function truncateMiddle(value: string, max: number): string {
  if (value.length <= max) return value;
  const left = Math.ceil((max - 3) / 2);
  const right = Math.floor((max - 3) / 2);
  return `${value.slice(0, left)}...${value.slice(value.length - right)}`;
}

Office.onReady(() => {
  document.getElementById("closeBtn")?.addEventListener("click", () => send({ action: "close" }));
  document.getElementById("moreMenu")?.addEventListener("change", async (event) => {
    const value = (event.target as HTMLSelectElement).value;
    if (value === "expand") expanded = new Set(rows.filter((row) => row.hasChildren).map((row) => row.id));
    if (value === "collapse") expanded = new Set(["root"]);
    if (value === "copyFormula") await navigator.clipboard.writeText(rawFormula);
    if (value === "copyTree") await navigator.clipboard.writeText(copyTreeAsText());
    (event.target as HTMLSelectElement).value = "";
    render();
  });
  Office.context.ui.addHandlerAsync(Office.EventType.DialogParentMessageReceived, (arg) => {
    const message = parseMessage("message" in arg ? arg.message : null);
    if (!message) return;
    if (message.action === "setTree") applyTree(message);
    if (message.action === "appendChildren") appendChildren(message);
    if (message.action === "error") {
      const status = document.getElementById("status");
      if (status) status.textContent = message.message;
    }
  }, () => send({ action: "ready" }));
});
